+
+fn select_core_contains_prepared_dispatch_subquery(core: &SelectCore, conn: &Connection) -> bool {
+    match core {
+        SelectCore::Select {
+            columns,
+            where_clause,
+            having,
+            ..
+        } => {
+            columns.iter().any(|column| match column {
+                ResultColumn::Expr { expr, .. } => {
+                    expr_requires_prepared_select_dispatch(expr, conn)
+                }
+                ResultColumn::Star | ResultColumn::TableStar(_) => false,
+            }) || where_clause
+                .as_ref()
+                .is_some_and(|expr| expr_requires_prepared_select_dispatch(expr, conn))
+                || having
+                    .as_ref()
+                    .is_some_and(|expr| expr_requires_prepared_select_dispatch(expr, conn))
+        }
+        SelectCore::Values(_) => false,
+    }
+}
+
+fn expr_requires_prepared_select_dispatch(expr: &Expr, conn: &Connection) -> bool {
+    match expr {
+        Expr::Exists { subquery, .. } => !exists_subquery_supported_by_vdbe(subquery, conn),
+        Expr::Subquery(subquery, _) => !scalar_subquery_supported_by_vdbe(subquery, conn),
+        Expr::BinaryOp { left, right, .. } => {
+            expr_requires_prepared_select_dispatch(left, conn)
+                || expr_requires_prepared_select_dispatch(right, conn)
+        }
+        Expr::UnaryOp { expr, .. }
+        | Expr::IsNull { expr, .. }
+        | Expr::Cast { expr, .. }
+        | Expr::Collate { expr, .. } => expr_requires_prepared_select_dispatch(expr, conn),
+        Expr::Between {
+            expr, low, high, ..
+        } => {
+            expr_requires_prepared_select_dispatch(expr, conn)
+                || expr_requires_prepared_select_dispatch(low, conn)
+                || expr_requires_prepared_select_dispatch(high, conn)
+        }
+        Expr::In { expr, set, .. } => {
+            matches!(expr.as_ref(), Expr::RowValue(..))
+                || expr_requires_prepared_select_dispatch(expr, conn)
+                || match set {
+                    InSet::List(exprs) => exprs
+                        .iter()
+                        .any(|item| expr_requires_prepared_select_dispatch(item, conn)),
+                    InSet::Subquery(subquery) => !in_subquery_supported_by_vdbe(subquery, conn),
+                    InSet::Table(_) => false,
+                }
+        }
+        Expr::Case {
+            operand,
+            whens,
+            else_expr,
+            ..
+        } => {
+            operand
+                .as_ref()
+                .is_some_and(|inner| expr_requires_prepared_select_dispatch(inner, conn))
+                || whens.iter().any(|(when_expr, then_expr)| {
+                    expr_requires_prepared_select_dispatch(when_expr, conn)
+                        || expr_requires_prepared_select_dispatch(then_expr, conn)
+                })
+                || else_expr
+                    .as_ref()
+                    .is_some_and(|inner| expr_requires_prepared_select_dispatch(inner, conn))
+        }
+        Expr::FunctionCall {
+            args: FunctionArgs::List(exprs),
+            ..
+        } => exprs
+            .iter()
+            .any(|inner| expr_requires_prepared_select_dispatch(inner, conn)),
+        Expr::Like {
+            expr,
+            pattern,
+            escape,
+            ..
+        } => {
+            expr_requires_prepared_select_dispatch(expr, conn)
+                || expr_requires_prepared_select_dispatch(pattern, conn)
+                || escape
+                    .as_ref()
+                    .is_some_and(|inner| expr_requires_prepared_select_dispatch(inner, conn))
+        }
+        Expr::Literal(_, _)
+        | Expr::Column(_, _)
+        | Expr::FunctionCall {
+            args: FunctionArgs::Star,
+            ..
+        }
+        | Expr::Placeholder(_, _)
+        | Expr::Raise { .. }
+        | Expr::JsonAccess { .. }
+        | Expr::RowValue(_, _) => false,
+    }
+}
