+fn exists_subquery_supported_by_vdbe(sub: &SelectStatement, conn: &Connection) -> bool {
+    if subquery_references_view(sub, conn)
+        || sub.with.is_some()
+        || !sub.body.compounds.is_empty()
+        || !sub.order_by.is_empty()
+        || sub.limit.is_some()
+    {
+        return false;
+    }
+
+    match &sub.body.select {
+        SelectCore::Select {
+            from,
+            group_by,
+            having,
+            windows,
+            ..
+        } => {
+            if !group_by.is_empty() || having.is_some() || !windows.is_empty() {
+                return false;
+            }
+            from.as_ref().is_none_or(|from_clause| {
+                from_clause.joins.is_empty()
+                    && matches!(&from_clause.source, TableOrSubquery::Table { .. })
+            })
+        }
+        SelectCore::Values(_) => false,
+    }
+}
+
+fn scalar_subquery_supported_by_vdbe(sub: &SelectStatement, conn: &Connection) -> bool {
+    if subquery_references_view(sub, conn)
+        || sub.with.is_some()
+        || !sub.body.compounds.is_empty()
+        || !sub.order_by.is_empty()
+        || sub.limit.is_some()
+    {
+        return false;
+    }
+
+    match &sub.body.select {
+        SelectCore::Select {
+            columns,
+            from,
+            group_by,
+            having,
+            windows,
+            ..
+        } => {
+            if columns.len() != 1 || !group_by.is_empty() || having.is_some() || !windows.is_empty()
+            {
+                return false;
+            }
+            from.as_ref().is_none_or(|from_clause| {
+                from_clause.joins.is_empty()
+                    && matches!(&from_clause.source, TableOrSubquery::Table { .. })
+            })
+        }
+        SelectCore::Values(_) => false,
+    }
+}
+
+fn in_subquery_supported_by_vdbe(sub: &SelectStatement, conn: &Connection) -> bool {
+    if in_subquery_needs_eager_eval(sub) || in_subquery_references_view(sub, conn) {
+        return false;
