+            }
+            matches!(
+                columns.as_slice(),
+                [ResultColumn::Expr { .. }] | [ResultColumn::Star] | [ResultColumn::TableStar(_)]
+            )
+        }
+        SelectCore::Values(_) => false,
+    }
+}
