+        from,
+        where_clause: Some(sub_where),
+        group_by,
+        having,
+        windows,
+        ..
+    } = &subquery.body.select
+    else {
+        return None;
+    };
+    if !group_by.is_empty() || having.is_some() || !windows.is_empty() {
+        return None;
